var skillName = "active.detonate_explosive_charge";
var skillOpt = Templates.All<SkillTemplate>().FirstOrDefault(s => s.name == skillName);
Assert.NotNull(skillOpt, $"Skill/Perk '{skillName}' should exist");
skillOpt

var handlers = skillOpt.EventHandlers;
Assert.NotNull(handlers, "EventHandlers should not be null");
Assert.True(handlers.Count > 0, "Should have at least one EventHandler");
var handler = handlers.FirstOrDefault(h => h._type == "RecallTarget");
Assert.NotNull(handler, $"Should find RecallTarget EventHandler");
handler

var fieldValue = handler.UseLastTargetOfSkill;
Assert.NotNull(fieldValue, "UseLastTargetOfSkill should be populated");
fieldValue
